class Solution:
    def insertGreatestCommonDivisors(self, head):
        import math
        if head is None or head.next is None:
            return head
        node = head
        vals = []
        while node:
            vals.append(node.val)
            node = node.next
        result_vals = [vals[0]]
        for i in range(1, len(vals)):
            result_vals.append(math.gcd(vals[i - 1], vals[i]))
            result_vals.append(vals[i])
        dummy = ListNode(0)
        tail = dummy
        for v in result_vals:
            tail.next = ListNode(v)
            tail = tail.next
        return dummy.next

