class Solution:
    def insertGreatestCommonDivisors(self, head):
        import math
        cur = head
        while cur and cur.next:
            g = math.gcd(cur.val, cur.next.val)
            new_node = ListNode(g, cur.next)
            cur.next = new_node
            cur = new_node.next
        return head

