var insertGreatestCommonDivisors = function(head) {
    function gcd(a, b) {
        while (b !== 0) {
            [a, b] = [b, a % b];
        }
        return a;
    }

    let cur = head;
    while (cur && cur.next) {
        const g = gcd(cur.val, cur.next.val);
        const newNode = new ListNode(g, cur.next);
        cur.next = newNode;
        cur = newNode.next;
    }
    return head;
};
